// tsconfig.lib.json (Angular library)
{
  "compilerOptions": {
    "declaration": true,          // emit .d.ts
    "declarationMap": true,       // emit .d.ts.map for IDE source navigation
    "declarationDir": "dist/types", // where .d.ts files go
    "emitDeclarationOnly": false  // also emit .js
  }
}

// Running tsc on a simple file:
// input:  src/math.ts
// output: dist/math.js + dist/math.d.ts

// src/math.ts
export function add(a: number, b: number): number { return a + b; }
export const PI = 3.14159;
export interface Point { x: number; y: number; }

// Generated dist/math.d.ts
export declare function add(a: number, b: number): number;
export declare const PI = 3.14159;
export interface Point { x: number; y: number; }

// typings/legacy-utils.d.ts
declare module 'legacy-utils' {
  export function formatCurrency(amount: number, currency: string): string;
  export function parseDate(input: string): Date;
  export const VERSION: string;

  export interface Config {
    locale: string;
    timezone: string;
  }

  export function configure(config: Config): void;

  // Default export
  export default class LegacyClient {
    constructor(apiKey: string);
    request(endpoint: string): Promise<unknown>;
  }
}

// typings/globals.d.ts
// For values injected into the global scope (e.g. by a <script> tag)

declare const __APP_VERSION__: string;   // injected at build time
declare const __API_BASE__: string;

declare interface Window {
  // Extend the built-in Window interface
  analyticsLayer: unknown[];
  gtag?: (...args: unknown[]) => void;
}

// Usage in a .ts file (no import needed)
console.log(__APP_VERSION__);
window.analyticsLayer.push({ event: 'page_view' });

# Install runtime + types
npm install lodash
npm install --save-dev @types/lodash

# TypeScript finds types in node_modules/@types/ automatically
# (typeRoots / types in tsconfig can restrict this)

// Usage after installing @types/lodash:
import { chunk, debounce } from 'lodash';
const pages = chunk([1,2,3,4,5,6], 2); // number[][] — fully typed
const debouncedSearch = debounce((q: string) => search(q), 300);

// dist/math.d.ts.map — generated alongside math.d.ts
{
  "version": 3,
  "file": "math.d.ts",
  "sourceRoot": "",
  "sources": ["../src/math.ts"],
  "names": [],
  "mappings": "..."
}

// In angular.json — ng build --configuration production emits these by default
// for libraries, allowing library consumers to navigate to library source

// projects/my-lib/src/public-api.ts
// Everything exported here ends up in the library's .d.ts
export { ButtonComponent } from './lib/button/button.component';
export { InputComponent } from './lib/input/input.component';
export type { ButtonVariant } from './lib/button/button.types';
// Internal helpers are NOT re-exported — consumers can't see or import them

// src/app/core/environment.d.ts — augment the environment type
declare module '@env/environment' {
  interface Environment {
    production: boolean;
    apiUrl: string;
    featureFlags: {
      darkMode: boolean;
      betaFeatures: boolean;
    };
  }

  export const environment: Environment;
}

// typings/formatter.d.ts
declare module 'formatter' {
  // Overloads describe different call signatures
  function format(value: number): string;
  function format(value: Date, locale: string): string;
  function format(value: string, template: string): string;

  export = format;
}

declare module 'builder' {
  class Query {
    private constructor(); // cannot be new'd directly
    static create(): Query;
    where(condition: string): this;
    limit(n: number): this;
    execute(): Promise<unknown[]>;
  }
  export = Query;
}

// tsconfig.lib.json — Angular library build config (partial)
{
  "compilerOptions": {
    "declaration": true,           // emit a .d.ts alongside every .js
    "declarationMap": true,        // emit .d.ts.map for IDE source navigation
    "declarationDir": "../../dist/my-lib/types",  // separate output dir for .d.ts files
    "emitDeclarationOnly": false,  // also emit .js (set true if another tool handles JS)
    "stripInternal": true          // omit @internal tagged declarations from .d.ts output
  }
}

// tsconfig.json — root project
{
  "compilerOptions": {
    "composite": true,             // enables project references (required for declarationMap)
    "incremental": true            // cache incremental rebuild — faster repeated compiles
  }
}

export class UserService {
  /** @internal */
  _cache: Map<string, User> = new Map(); // hidden from .d.ts — library-internal only

  getUser(id: string): Promise<User | undefined> {
    return Promise.resolve(this._cache.get(id));
  }
}

// Generated .d.ts with stripInternal: true:
export declare class UserService {
  // _cache is not present — stripped
  getUser(id: string): Promise<User | undefined>;
}

// src/polyfills.ts — pull in Node.js types without an import statement
/// <reference types="node" />

process.env['NODE_ENV']; // now typed without importing anything

// typings/global-extensions.d.ts — extend DOM types
/// <reference lib="dom" />

interface HTMLElement {
  // add a custom property all your app's elements will have
  _appData?: Record<string, unknown>;
}

// A library's index.d.ts may include this to pull in dependencies:
/// <reference types="zone.js" />

// typings/deep-utils.d.ts — utility types commonly found in library .d.ts files

// Recursively make all properties optional
export type DeepPartial<T> = T extends object
  ? { [K in keyof T]?: DeepPartial<T[K]> }
  : T;

// Extract only function properties from a type
export type FunctionKeys<T> = {
  [K in keyof T]: T[K] extends (...args: unknown[]) => unknown ? K : never;
}[keyof T];

// Flatten nested promise
export type Awaited<T> = T extends Promise<infer U> ? Awaited<U> : T;

// Usage in consumer code (types come from the .d.ts, no runtime code)
interface Config { name: string; options: { debug: boolean; retries: number } }
type PartialConfig = DeepPartial<Config>;
// PartialConfig = { name?: string; options?: { debug?: boolean; retries?: number } }

// A CommonJS library:  module.exports = function chalk(text) { ... }
// chalk.red = function(...) { ... }
// chalk.bold = function(...) { ... }

// Correct .d.ts for a CJS module:
declare function chalk(text: string): string;

declare namespace chalk {
  // Properties on the exported function itself
  function red(text: string): string;
  function green(text: string): string;
  function bold(text: string): string;
  const level: 0 | 1 | 2 | 3;
}

// export = matches: const chalk = require('chalk')
export = chalk;

// Consumer:
import chalk = require('chalk');       // CommonJS-style TypeScript import
// OR (with esModuleInterop: true):
import chalk from 'chalk';             // treated as default import
console.log(chalk.red('Error!'));

// typings/http-client.d.ts — structural typing in declarations
declare module 'simple-http' {
  // Any object with these two methods satisfies RequestOptions
  interface RequestOptions {
    headers?: Record<string, string>;
    timeout?: number;
  }

  // Return type is structural — any object with these keys
  interface Response<T = unknown> {
    status: number;
    data: T;
    headers: Record<string, string>;
  }

  // The function accepts anything matching RequestOptions (structural)
  export function get<T = unknown>(url: string, opts?: RequestOptions): Promise<Response<T>>;
  export function post<T = unknown>(url: string, body: unknown, opts?: RequestOptions): Promise<Response<T>>;
}

// Consumer gets full type inference:
import { get } from 'simple-http';
const response = await get<{ users: string[] }>('/api/users');
//    ^? Promise<Response<{ users: string[] }>>
response.data.users.forEach(u => console.log(u)); // typed: string[]

// dist/my-lib/package.json — generated by ng-packagr
{
  "name": "my-lib",
  "version": "1.0.0",
  "main": "fesm2022/my-lib.mjs",
  "typings": "index.d.ts",           // <-- TypeScript reads this
  "exports": {
    ".": {
      "types": "./index.d.ts",       // modern package exports field
      "default": "./fesm2022/my-lib.mjs"
    }
  }
}

// dist/my-lib/index.d.ts — generated entry point
export * from './lib/button/button.component';
export * from './lib/input/input.component';
export type * from './lib/types';
// Angular-specific metadata emitted by ngc:
export { ButtonComponent as ɵButtonComponent } from './lib/button/button.component';
// (ɵ prefix = Angular internal — not part of your public API)

// Diagnosing 'could not find declaration file' — workaround options

// Option 1: install @types
npm install --save-dev @types/lodash

// Option 2: ambient module — minimal typing
// typings/lodash-partial.d.ts
declare module 'lodash' {
  export function debounce<T extends (...a: unknown[]) => unknown>(fn: T, ms: number): T;
  export function chunk<T>(arr: T[], size: number): T[][];
}

// Option 3: suppress error for a specific module (use sparingly)
declare module 'some-untyped-module';
// Now any import from 'some-untyped-module' succeeds — but returns 'any'

// Finding where TypeScript is reading .d.ts from:
// tsc --traceResolution 2>&1 | grep declaration-files-module

// Testing a component that uses an ambient global
// typings/globals.d.ts
declare const __APP_VERSION__: string;

// karma.conf.js or jest.config.ts — inject the global
// For Jest:
globals: {
  __APP_VERSION__: '1.0.0-test'
}

// my.component.spec.ts
it('shows the version', () => {
  // __APP_VERSION__ is available in test because Jest injected it
  const fixture = TestBed.createComponent(MyComponent);
  fixture.detectChanges();
  expect(fixture.nativeElement.textContent).toContain('1.0.0-test');
});

// Testing a service from a library (consuming its .d.ts)
import { MyLibraryService } from 'my-library';   // TypeScript reads dist/index.d.ts

describe('MyLibraryService', () => {
  let service: MyLibraryService;

  beforeEach(() => TestBed.configureTestingModule({
    providers: [MyLibraryService]
  }));

  beforeEach(() => service = TestBed.inject(MyLibraryService));

  it('works', () => {
    // type-safe because .d.ts describes the API
    expect(service.greet('Alice')).toBe('Hello, Alice!');
  });
});
